#\n# @lc app=leetcode id=3575 lang=python3\n#\n# [3575] Maximum Good Subtree Score\n#\n\n# @lc code=start\nclass Solution:\n    def goodSubtreeSum(self, vals: List[int], par: List[int]) -> int:\n        from collections import defaultdict\n        MOD = 10**9 + 7\n        n = len(vals)\n        # Create an adjacency list for tree representation\n        tree = defaultdict(list)\n        for child, parent in enumerate(par):\n            if parent != -1:\n                tree[parent].append(child)\n        \n        # Memoization table to store max score for each subtree rooted at node\n        memo = [-1] * n\n        \t      \t# Helper function to calculate max score for a subtree rooted at `node`      \tdef dfs(node):              # If already computed, return it          if memo[node] != -1:              return memo[node]          used_digits = set() # Track used digits in current path          current_score = vals[node]          # Convert value to str and add digits to used set          local_used_digits = set(str(vals[node]))          used_digits.update(local_used_digits)          child_scores = [] # Store children's valid scores separately          for child in tree[node]:              child_score = dfs(child)              # Check if we can add child's score without adding repeated digits.              if not local_used_digits.intersection(set(str(vals[child]))):                  local_used_digits.update(set(str(vals[child])))                  current_score += child_score                  child_scores.append(current_score)              else:                  # Consider only child's score as separate good subset                   child_scores.append(child_score)            max_score = max([current_score] + child_scores)   # Max valid score including self or children only          memo[node] = max_score               return max_score      total_sum = 0      \tfor node in range(n):          total_sum += dfs(node)      \treturn total_sum % MOD    # Return result modulo 10**9 + 7    # @lc code=end